/**
 * Email notification adapter.
 *
 * Implements the NotificationAdapter interface for email delivery.
 * Supports template rendering, recipient resolution, and pluggable
 * email transport (SMTP, SendGrid, SES, etc.).
 *
 * CONSTRAINT: All adapters must implement the NotificationAdapter interface
 * from src/models/notification.ts. Register adapters with NotificationService
 * via registerAdapter().
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents a rendered email ready for sending.
 */
export interface EmailMessage {
  from: string;
  replyTo?: string;
  to: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport interface for actually sending emails.
 * Implement this for SMTP, SendGrid, SES, etc.
 */
export interface EmailTransport {
  sendMail(message: EmailMessage): Promise<{ messageId: string }>;
}

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** Sender address for outgoing emails. */
  fromAddress: string;
  /** Optional reply-to address. */
  replyToAddress?: string;
  /** Email transport implementation. If not provided, uses a logging-only transport. */
  transport?: EmailTransport;
}

/**
 * Template data structure used for rendering email templates.
 */
interface TemplateData {
  recipient: string;
  subject: string;
  body: string;
  metadata: Record<string, string>;
}

/**
 * Email templates keyed by notification type.
 * Each template has an HTML and plain text renderer.
 */
const EMAIL_TEMPLATES: Record<
  NotificationType,
  {
    renderHtml: (data: TemplateData) => string;
    renderText: (data: TemplateData) => string;
  }
> = {
  order_confirmation: {
    renderHtml: (data) =>
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">` +
      `<h1 style="color: #2563eb;">Order Confirmation</h1>` +
      `<p>Hello,</p>` +
      `<p>${escapeHtml(data.body)}</p>` +
      (data.metadata.orderId
        ? `<p style="color: #6b7280; font-size: 0.875rem;">Order ID: ${escapeHtml(data.metadata.orderId)}</p>`
        : '') +
      `<hr style="border-color: #e5e7eb;" />` +
      `<p style="color: #9ca3af; font-size: 0.75rem;">This is an automated message. Please do not reply directly.</p>` +
      `</div>`,
    renderText: (data) =>
      `Order Confirmation\n\n${data.body}\n\n` +
      (data.metadata.orderId ? `Order ID: ${data.metadata.orderId}\n\n` : '') +
      `This is an automated message. Please do not reply directly.`,
  },
  order_status_update: {
    renderHtml: (data) =>
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">` +
      `<h1 style="color: #2563eb;">Order Status Update</h1>` +
      `<p>Hello,</p>` +
      `<p>${escapeHtml(data.body)}</p>` +
      (data.metadata.orderId
        ? `<p style="color: #6b7280; font-size: 0.875rem;">Order ID: ${escapeHtml(data.metadata.orderId)}</p>`
        : '') +
      (data.metadata.newStatus
        ? `<p><strong>New Status:</strong> ${escapeHtml(data.metadata.newStatus)}</p>`
        : '') +
      `<hr style="border-color: #e5e7eb;" />` +
      `<p style="color: #9ca3af; font-size: 0.75rem;">This is an automated message. Please do not reply directly.</p>` +
      `</div>`,
    renderText: (data) =>
      `Order Status Update\n\n${data.body}\n\n` +
      (data.metadata.orderId ? `Order ID: ${data.metadata.orderId}\n` : '') +
      (data.metadata.newStatus ? `New Status: ${data.metadata.newStatus}\n\n` : '\n') +
      `This is an automated message. Please do not reply directly.`,
  },
  welcome: {
    renderHtml: (data) =>
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">` +
      `<h1 style="color: #2563eb;">Welcome to TaskFlow Pro!</h1>` +
      `<p>${escapeHtml(data.body)}</p>` +
      `<p>We're excited to have you on board.</p>` +
      `<hr style="border-color: #e5e7eb;" />` +
      `<p style="color: #9ca3af; font-size: 0.75rem;">This is an automated message. Please do not reply directly.</p>` +
      `</div>`,
    renderText: (data) =>
      `Welcome to TaskFlow Pro!\n\n${data.body}\n\nWe're excited to have you on board.\n\n` +
      `This is an automated message. Please do not reply directly.`,
  },
  account_updated: {
    renderHtml: (data) =>
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">` +
      `<h1 style="color: #2563eb;">Account Updated</h1>` +
      `<p>Hello,</p>` +
      `<p>${escapeHtml(data.body)}</p>` +
      `<hr style="border-color: #e5e7eb;" />` +
      `<p style="color: #9ca3af; font-size: 0.75rem;">This is an automated message. Please do not reply directly.</p>` +
      `</div>`,
    renderText: (data) =>
      `Account Updated\n\n${data.body}\n\n` +
      `This is an automated message. Please do not reply directly.`,
  },
};

/**
 * Escape HTML special characters to prevent XSS in email templates.
 */
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

/**
 * Resolve the recipient email address from a notification payload.
 * The recipient field may be an email address directly or a user ID.
 * If it looks like an email (contains @), use it directly.
 * Otherwise, it's treated as an identifier that needs external resolution
 * (for now, we return it as-is since the notification service should
 * provide resolved emails).
 */
function resolveRecipient(recipient: string): string {
  return recipient.trim();
}

/**
 * A logging-only transport used when no real transport is configured.
 * Useful for development and testing.
 */
class LoggingTransport implements EmailTransport {
  private logger = new Logger('LoggingTransport');
  private sentMessages: EmailMessage[] = [];

  async sendMail(message: EmailMessage): Promise<{ messageId: string }> {
    const messageId = `log-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    this.logger.info(`[DRY RUN] Email to=${message.to} subject="${message.subject}" id=${messageId}`);
    this.sentMessages.push(message);
    return { messageId };
  }

  getSentMessages(): EmailMessage[] {
    return [...this.sentMessages];
  }
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;

  constructor(private config: EmailAdapterConfig) {
    this.transport = config.transport ?? new LoggingTransport();
  }

  /**
   * Render the notification payload into a full EmailMessage using the
   * appropriate template for the notification type.
   */
  renderEmail(payload: NotificationPayload): EmailMessage {
    const resolvedRecipient = resolveRecipient(payload.recipient);
    const templateData: TemplateData = {
      recipient: resolvedRecipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata ?? {},
    };

    const template = EMAIL_TEMPLATES[payload.notificationType];

    return {
      from: this.config.fromAddress,
      replyTo: this.config.replyToAddress,
      to: resolvedRecipient,
      subject: payload.subject,
      html: template.renderHtml(templateData),
      text: template.renderText(templateData),
    };
  }

  /**
   * Send a notification via email.
   *
   * Renders the email using the notification type's template, resolves the
   * recipient, and dispatches via the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const email = this.renderEmail(payload);
      this.logger.info(`Sending email to ${email.to}: "${email.subject}" (from: ${this.config.fromAddress})`);

      const result = await this.transport.sendMail(email);
      this.logger.info(`Email sent successfully: messageId=${result.messageId}`);

      return {
        success: true,
        channel: this.channel,
      };
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown email transport error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        error: errorMessage,
      };
    }
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { EmailTransport, EmailMessage } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    notificationType: 'order_confirmation',
    channel: 'email',
    priority: 'normal',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

function createMockTransport() {
  const sent: EmailMessage[] = [];
  const transport: EmailTransport = {
    async sendMail(message: EmailMessage) {
      sent.push(message);
      return { messageId: `mock-${sent.length}` };
    },
  };
  return { transport, sent };
}

describe('EmailAdapter', () => {
  describe('constructor', () => {
    it('should set the channel to email', () => {
      const adapter = new EmailAdapter({ fromAddress: 'noreply@test.com' });
      expect(adapter.channel).toBe('email');
    });
  });

  describe('renderEmail', () => {
    let adapter: EmailAdapter;

    beforeEach(() => {
      adapter = new EmailAdapter({
        fromAddress: 'noreply@taskflow.com',
        replyToAddress: 'support@taskflow.com',
      });
    });

    it('should render order_confirmation template with HTML and text', () => {
      const payload = makePayload();
      const email = adapter.renderEmail(payload);

      expect(email.from).toBe('noreply@taskflow.com');
      expect(email.replyTo).toBe('support@taskflow.com');
      expect(email.to).toBe('alice@example.com');
      expect(email.subject).toBe('Order Confirmation: order-1');
      expect(email.html).toContain('Order Confirmation');
      expect(email.html).toContain('Widget x2');
      expect(email.html).toContain('Order ID: order-1');
      expect(email.text).toContain('Order Confirmation');
      expect(email.text).toContain('Widget x2');
      expect(email.text).toContain('Order ID: order-1');
    });

    it('should render order_status_update template', () => {
      const payload = makePayload({
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
        notificationType: 'order_status_update',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('Order Status Update');
      expect(email.html).toContain('pending to confirmed');
      expect(email.html).toContain('New Status:');
      expect(email.html).toContain('confirmed');
      expect(email.text).toContain('New Status: confirmed');
    });

    it('should render welcome template', () => {
      const payload = makePayload({
        subject: 'Welcome!',
        body: 'Welcome aboard, Alice!',
        notificationType: 'welcome',
        metadata: {},
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('Welcome to TaskFlow Pro');
      expect(email.html).toContain('Welcome aboard, Alice!');
      expect(email.text).toContain('excited to have you on board');
    });

    it('should render account_updated template', () => {
      const payload = makePayload({
        subject: 'Account Updated',
        body: 'Your account settings have been updated.',
        notificationType: 'account_updated',
        metadata: {},
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('Account Updated');
      expect(email.html).toContain('account settings have been updated');
      expect(email.text).toContain('Account Updated');
    });

    it('should escape HTML in body to prevent XSS', () => {
      const payload = makePayload({
        body: '<script>alert("xss")</script>',
      });
      const email = adapter.renderEmail(payload);

      expect(email.html).not.toContain('<script>');
      expect(email.html).toContain('&lt;script&gt;');
    });

    it('should trim whitespace from recipient', () => {
      const payload = makePayload({ recipient: '  alice@example.com  ' });
      const email = adapter.renderEmail(payload);

      expect(email.to).toBe('alice@example.com');
    });

    it('should omit replyTo when not configured', () => {
      const adapterNoReply = new EmailAdapter({ fromAddress: 'noreply@test.com' });
      const email = adapterNoReply.renderEmail(makePayload());

      expect(email.replyTo).toBeUndefined();
    });

    it('should handle missing metadata gracefully', () => {
      const payload = makePayload({ metadata: undefined });
      const email = adapter.renderEmail(payload);

      expect(email.html).toContain('Order Confirmation');
      // Should not include Order ID line when metadata is empty
      expect(email.html).not.toContain('Order ID:');
    });
  });

  describe('send', () => {
    it('should send email through the transport and return success', async () => {
      const { transport, sent } = createMockTransport();
      const adapter = new EmailAdapter({
        fromAddress: 'noreply@taskflow.com',
        transport,
      });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.error).toBeUndefined();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.to).toBe('alice@example.com');
      expect(sent[0]!.subject).toBe('Order Confirmation: order-1');
      expect(sent[0]!.from).toBe('noreply@taskflow.com');
    });

    it('should return failure when transport throws', async () => {
      const transport: EmailTransport = {
        async sendMail() {
          throw new Error('SMTP connection refused');
        },
      };
      const adapter = new EmailAdapter({
        fromAddress: 'noreply@taskflow.com',
        transport,
      });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('email');
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should handle non-Error throws gracefully', async () => {
      const transport: EmailTransport = {
        async sendMail() {
          throw 'string error';
        },
      };
      const adapter = new EmailAdapter({
        fromAddress: 'noreply@taskflow.com',
        transport,
      });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown email transport error');
    });

    it('should use logging transport when no transport is provided', async () => {
      const adapter = new EmailAdapter({ fromAddress: 'noreply@taskflow.com' });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
    });

    it('should render the correct template before sending', async () => {
      const { transport, sent } = createMockTransport();
      const adapter = new EmailAdapter({
        fromAddress: 'noreply@taskflow.com',
        transport,
      });

      await adapter.send(
        makePayload({
          notificationType: 'welcome',
          subject: 'Welcome!',
          body: 'Hi Alice!',
        }),
      );

      expect(sent[0]!.html).toContain('Welcome to TaskFlow Pro');
      expect(sent[0]!.text).toContain('Hi Alice!');
    });
  });

  describe('integration with NotificationService pattern', () => {
    it('should conform to the NotificationAdapter interface', async () => {
      const { transport } = createMockTransport();
      const adapter = new EmailAdapter({
        fromAddress: 'noreply@taskflow.com',
        transport,
      });

      // Verify it has the required shape
      expect(adapter.channel).toBe('email');
      expect(typeof adapter.send).toBe('function');

      // Verify send returns the correct shape
      const result = await adapter.send(makePayload());
      expect(result).toHaveProperty('success');
      expect(result).toHaveProperty('channel');
    });
  });
});
